#include <iostream>

class Color {
    int m_r;
    int m_g;
    int m_b;
public:
    Color(int r, int g, int b)
        : m_r{ r }, m_g{ g }, m_b{ b }
    {}

    int r() const { return m_r; }
    int g() const { return m_g; }
    int b() const { return m_b; }
};

void printColor(const Color& c) {
    std::cout << "(" << c.r() << ", " << c.g() << ", " << c.b() << ")\n";
}

int main() {
    int r{}, g{}, b{};
    std::cin >> r >> g >> b;
    std::cout << "Default: ";
    printColor(Color{ 0, 0, 0 });
    std::cout << "Custom: ";
    printColor(Color{ r, g, b });
}

