solution_code:
#include <iostream>

class Num {
    int m_val;
public:
    Num(int v) : m_val{ v } {}
    int get() const { return m_val; }
};

int doubled(const Num& n) {
    return n.get() * 2;
}

int main() {
    int n{};
    std::cin >> n;
    std::cout << "Doubled: " << doubled(Num{ n }) << "\n";
}
